parameters.jsonBody:
={{
{
  "model": "mistral-small-latest",
  "messages": [
    {
      "role": "system",
      "content": "Tu es l'application MEMO. Rédige en Français. Ton style est immersif et journalistique. Réponds UNIQUEMENT en JSON."
    },
    {
      "role": "user",
      "content": "Rédige une anecdote historique pour le " + $now.format('dd MMMM') + ". \n\nSTRUCTURE JSON OBLIGATOIRE :\n{\n  \"titre\": \"...\",\n  \"p1\": \"1er paragraphe (HTML <p>)\",\n  \"p2\": \"2ème paragraphe (HTML <p>)\",\n  \"p3\": \"3ème paragraphe (HTML <p>)\",\n  \"keywords\": \"3 mots-clés anglais séparés par des virgules illustrant les 3 phases de l'histoire\",\n  \"conclusion\": \"Conclusion (HTML <i>)\"\n}"
    }
  ],
  "response_format": { "type": "json_object" },
  "temperature": 0.7
}
}}

parameters.message:
={{
(() => {
  // 1. On récupère les données des nœuds parents
  const nodeMistral = $('SITE INTERNET ANECDOTE');
  const nodePexels = $('PEXELS');

  // 2. On parse le contenu de Mistral
  const memo = JSON.parse(nodeMistral.item.json.choices[0].message.content);

  // 3. On récupère la liste des photos
  const photos = nodePexels.item.json.photos;

  // Petite sécurité pour les images (si Pexels en manque une)
  const getImg = (i) => photos[i] ? photos[i].src.large : 'https://via.placeholder.com/600x300?text=MEMO+Image';

  return `
<div style="background-color: #f4f7f9; padding: 40px 10px; font-family: 'Georgia', serif;">
  <div style="max-width: 600px; margin: 0 auto; background-color: #ffffff; border-radius: 20px; overflow: hidden; box-shadow: 0 10px 30px rgba(0,0,0,0.05);">

    <img src="${getImg(0)}" style="width: 100%; height: auto; display: block; border-bottom: 4px solid #6366f1;">

    <div style="padding: 30px;">
      <h1 style="color: #1e293b; font-size: 26px; margin-top: 0; line-height: 1.2;">${memo.titre}</h1>

      <div style="color: #334155; line-height: 1.7; font-size: 16px;">
        ${memo.p1}
      </div>

      <img src="${getImg(1)}" style="width: 100%; border-radius: 12px; margin: 20px 0;">

      <div style="color: #334155; line-height: 1.7; font-size: 16px;">
        ${memo.p2}
      </div>

      <img src="${getImg(2)}" style="width: 100%; border-radius: 12px; margin: 20px 0;">

      <div style="color: #334155; line-height: 1.7; font-size: 16px;">
        ${memo.p3}
      </div>

      <p style="text-align: center; color: #64748b; font-style: italic; margin-top: 30px; border-top: 1px solid #f1f5f9; padding-top: 20px;">
        ${memo.conclusion}
      </p>

      <div style="margin-top: 40px; padding-top: 20px; border-top: 2px solid #6366f1; text-align: center;">
        <p style="color: #94a3b8; font-size: 11px; text-transform: uppercase; letter-spacing: 2px; margin: 0;">
          Intelligence Économique • Master 2 • Lucas Simatovic
        </p>
      </div>
    </div>
  </div>
</div>
  `;
})()
}}
